import { Router } from "express";
import { nodesController } from "./nodes.controller";
import { createNodeSchema, getNodeSchema, listNodeOpinionsSchema, listNodesSchema, updateNodeSchema, } from "./nodes.schema";
import { validate } from "../../middlewares/validate.middleware";
import { authenticateJwt, optionalAuthenticateJwt, } from "../../middlewares/auth.middleware";
const nodesRoutes = Router();
nodesRoutes.get("/", optionalAuthenticateJwt, validate(listNodesSchema), nodesController.list);
nodesRoutes.post("/", authenticateJwt, validate(createNodeSchema), nodesController.create);
nodesRoutes.get("/:id/opinions", optionalAuthenticateJwt, validate(listNodeOpinionsSchema), nodesController.listOpinions);
nodesRoutes.get("/:id", optionalAuthenticateJwt, validate(getNodeSchema), nodesController.getById);
nodesRoutes.patch("/:id", authenticateJwt, validate(updateNodeSchema), nodesController.update);
export { nodesRoutes };
